(function () {
  "use strict";
  const OA = window.OrbArena, esc = (value) => String(value ?? "").replace(/[&<>"']/g, (char) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[char]));
  class BuildUI {
    constructor(app) { this.app = app; this.system = app.buildSystem; this.ensure(); this.bind(); }
    ensure() { if (document.querySelector("#screen-build")) return; document.querySelector(".screen-stack").insertAdjacentHTML("beforeend", `<section class="screen module-screen" id="screen-build"><div class="module-page"><header class="module-head"><button class="back-button" data-go-home>← MENU</button><div><span class="eyebrow">04 · OFICINA TÁTICA · III</span><h1>CRIAR BUILD</h1><p>Combine personagem, equipamento e poderes dentro de um orçamento verificável.</p></div></header><div class="build-stepper"><span>1 Personagem</span><span>2 Arma</span><span>3 Habilidades</span><span>4 Perks</span><span>5 Balanceamento</span><span>6 Revisão</span></div><div class="build-layout"><form id="build-editor" class="panel module-form"></form><aside id="build-analysis" class="panel module-detail"></aside></div><div class="module-actions" id="build-actions"></div></div></section>`); }
    bind() { document.querySelector("#screen-build [data-go-home]").onclick = () => this.app.goHome(); document.querySelector("#build-editor").addEventListener("change", () => this.read()); document.querySelector("#build-editor").addEventListener("input", () => this.read()); }
    open(build = null) { this.app.game.stop(); this.app.state.currentBuild = this.system.create(build || this.app.state.currentBuild || {}); this.app.state.build = this.app.state.currentBuild; this.render(); this.app.showScreen("build"); }
    options(items, selected, label = "name") { return items.map((item) => `<option value="${esc(item.id)}" ${item.id === selected ? "selected" : ""}>${esc(item[label] || item.id)}</option>`).join(""); }
    render() { const b = this.app.state.currentBuild, ability = (slot) => `<label><span>${slot}</span><select data-ability="${slot}"><option value="">Nenhuma</option>${this.options(OA.CATALOG.abilities, b.abilities[slot])}</select></label>`; document.querySelector("#build-editor").innerHTML = `<label><span>Nome</span><input id="build-name" maxlength="48" value="${esc(b.name)}"></label><label><span>Descrição</span><textarea id="build-description" maxlength="240">${esc(b.description)}</textarea></label><label><span>Personagem</span><select id="build-character">${this.options(OA.CharacterRegistry.all(), b.characterId)}</select></label><label><span>Arma</span><select id="build-weapon">${this.options(OA.CATALOG.weapons, b.weaponId)}</select></label><div class="form-grid">${["active","secondary","passive","reactive","ultimate"].map(ability).join("")}</div><fieldset><legend>Perks · máximo 4</legend><div class="check-grid">${OA.CATALOG.perks.map((item) => `<label><input type="checkbox" data-perk="${item.id}" ${b.perks.includes(item.id) ? "checked" : ""}> ${esc(item.name)}</label>`).join("")}</div></fieldset><div class="form-grid"><label><span>Preset físico</span><select id="build-physics">${Object.values(OA.PHYSICS_PRESETS).map((item) => `<option value="${item.id}" ${item.id === b.physicsPreset ? "selected" : ""}>${esc(item.name)}</option>`).join("")}</select></label><label><span>Arena preferida</span><select id="build-arena">${Object.values(OA.ARENA_DEFINITIONS).map((item) => `<option value="${item.id}" ${item.id === b.arenaId ? "selected" : ""}>${esc(item.name)}</option>`).join("")}</select></label><label><span>Skin/cor</span><input id="build-skin" value="${esc(b.skin)}"></label><label><span>Tags</span><input id="build-tags" value="${esc(b.tags.join(", "))}"></label></div>`; this.renderAnalysis(); this.renderActions(); }
    read() { const b = this.app.state.currentBuild; b.name = document.querySelector("#build-name").value.trim() || "Build sem nome"; b.description = document.querySelector("#build-description").value.trim(); b.characterId = document.querySelector("#build-character").value; b.weaponId = document.querySelector("#build-weapon").value; document.querySelectorAll("[data-ability]").forEach((select) => { b.abilities[select.dataset.ability] = select.value || null; }); b.perks = [...document.querySelectorAll("[data-perk]:checked")].map((input) => input.dataset.perk); b.physicsPreset = document.querySelector("#build-physics").value; b.arenaId = document.querySelector("#build-arena").value; b.skin = document.querySelector("#build-skin").value.trim() || "default"; b.tags = document.querySelector("#build-tags").value.split(",").map((item) => item.trim()).filter(Boolean).slice(0, 8); this.renderAnalysis(); }
    renderAnalysis() { const b = this.app.state.currentBuild, check = this.system.validate(b); b.powerBudget = check.budget.total; const bars = ["offense","defense","mobility","control","sustain","summon","complexity","risk"].map((key) => `<div class="budget-row"><span>${key}</span><i><b style="width:${Math.min(100, check.budget[key] * 2.5)}%"></b></i><strong>${check.budget[key]}</strong></div>`).join(""); document.querySelector("#build-analysis").innerHTML = `<h2>POWER BUDGET <b>${check.budget.total}/${check.budget.limit}</b></h2>${bars}<div class="validation ${check.valid ? "valid" : "invalid"}"><h3>${check.valid ? "BUILD VÁLIDA" : "CORREÇÕES NECESSÁRIAS"}</h3>${[...check.errors, ...check.warnings].map((item) => `<p>${esc(item)}</p>`).join("") || "<p>Pronta para salvar ou testar.</p>"}</div><h3>SINERGIAS</h3>${check.synergy.strong.map((item) => `<span class="tag strong">${esc(item)}</span>`).join("") || "<p>Nenhuma sinergia forte detectada.</p>"}<h3>LEITURAS</h3>${[...check.synergy.medium, ...check.synergy.weaknesses].map((item) => `<span class="tag">${esc(item)}</span>`).join("")}`; }
    renderActions() { const actions = [["save","Salvar build"],["save-new","Salvar como nova"],["test","Testar build"],["random","Randomizar"],["clear","Limpar"],["duplicate","Duplicar"],["import","Importar"],["export","Exportar"],["compare","Comparar"],["favorite","Tornar favorita"]]; document.querySelector("#build-actions").innerHTML = actions.map(([id,label]) => `<button class="button ${id === "save" || id === "test" ? "button-primary" : "button-secondary"}" data-build-action="${id}">${label}</button>`).join(""); document.querySelectorAll("[data-build-action]").forEach((button) => button.onclick = () => this.action(button.dataset.buildAction)); }
    download(name, text) { const blob = new Blob([text], { type: "application/json" }), link = document.createElement("a"); link.href = URL.createObjectURL(blob); link.download = name; link.click(); URL.revokeObjectURL(link.href); }
    action(type) { const b = this.app.state.currentBuild; try { if (type === "save" || type === "save-new" || type === "duplicate") { const check = this.system.validate(b); if (!check.valid) throw new Error(check.errors.join(" ")); const saved = this.app.storage.saveBuild(b, type !== "save").value; this.app.state.currentBuild = saved; this.app.toast(type === "save" ? "Build salva." : "Variante criada.", "success"); this.render(); } else if (type === "test") { const check = this.system.validate(b); if (!check.valid) throw new Error(check.errors.join(" ")); this.app.startBattle({ ...b, color: OA.CharacterRegistry.get(b.characterId).color, stroke: OA.CharacterRegistry.get(b.characterId).glow, trailColor: OA.CharacterRegistry.get(b.characterId).secondary }, "normal", OA.Random.createSeed(), OA.getPhysicsPreset(b.physicsPreset), { arenaId: b.arenaId, mode: "build-test", temporary: true }); } else if (type === "random") { this.app.state.currentBuild = this.system.random("balanced", b.characterId); this.render(); this.app.toast("Build válida randomizada."); } else if (type === "clear") { this.app.state.currentBuild = this.system.create(); this.render(); } else if (type === "export") this.download(`${b.name.replace(/\W+/g,"-")}.json`, this.system.export(b)); else if (type === "import") { const text = prompt("Cole apenas o JSON da build:"); if (text) { this.app.state.currentBuild = this.system.import(text); this.render(); this.app.toast("Build importada.", "success"); } } else if (type === "favorite") { b.favorite = !b.favorite; this.app.toast(b.favorite ? "Build marcada como favorita." : "Favorito removido."); } else if (type === "compare") this.app.archiveUI.openBuilds(b.id); } catch (error) { this.app.toast(error.message, "error"); } }
  }
  OA.BuildUI = BuildUI;
}());
